import{_ as t,c as a,a1 as o,o as n}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Basic Network Troubleshooting using MegaPing (Windows)","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/2-scanning-networks/3-MegaPing.md","filePath":"categories/ethical-hacking-labs/2-scanning-networks/3-MegaPing.md"}'),r={name:"categories/ethical-hacking-labs/2-scanning-networks/3-MegaPing.md"};function i(s,e,c,l,g,h){return n(),a("div",null,e[0]||(e[0]=[o('<h1 id="basic-network-troubleshooting-using-megaping-windows" tabindex="-1">Basic Network Troubleshooting using MegaPing (Windows) <a class="header-anchor" href="#basic-network-troubleshooting-using-megaping-windows" aria-label="Permalink to &quot;Basic Network Troubleshooting using MegaPing (Windows)&quot;">​</a></h1><p>MegaPing is an ultimate toolkit that provides complete essential utilities for IT administrators and solution providers.</p><p>Official site: <a href="http://www.magnetosoft.com/product/megaping/download" target="_blank" rel="noreferrer">http://www.magnetosoft.com/product/megaping/download</a></p><p>With MegaPing utility, you can detect live hosts, open ports of the system in the network. You can also perform various network troubleshooting activities with the help of network utilities integrated into it, such as DNS lookup name, DNS list hosts, Finger, host monitor, IP scanner, NetBios scanner, network time synchronizer, ping, port scanner, share scanner, traceroute, and whois.</p><h3 id="objectives" tabindex="-1">Objectives: <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives:&quot;">​</a></h3><ul><li>Detect live hosts and open ports of systems in the network.</li></ul><h3 id="requirements" tabindex="-1">Requirements: <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements:&quot;">​</a></h3><ul><li>Windows 7, 8 or 10.</li><li>Windows Server 2012/2016 (target).</li></ul><hr><p>After the installation, launch the application on your Windows 10 machine.</p><h2 id="scanning-for-active-hosts" tabindex="-1">Scanning for Active Hosts <a class="header-anchor" href="#scanning-for-active-hosts" aria-label="Permalink to &quot;Scanning for Active Hosts&quot;">​</a></h2><p>This software is very simple to use. To start a scan click on <strong>IP Scanner</strong> on the left panel.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/2e4f6b59a182462ca77ffd6888b14e0eeede313d/megaPing.png" alt="alt text" title="MegaPing"></p><ul><li>Specify the <strong>IP Range</strong> of your network lab, then click start.</li><li>Note the check box on the right side, you can view the <strong>MAC addresses</strong> from the hosts you harvested.</li></ul><p>MegaPing list down all the IP addresses under the specified target range with their <strong>TTL</strong>, <strong>Status</strong>(dead or alive), and their statistics.</p><h2 id="perform-traceroute-on-a-target" tabindex="-1">Perform Traceroute on a Target <a class="header-anchor" href="#perform-traceroute-on-a-target" aria-label="Permalink to &quot;Perform Traceroute on a Target&quot;">​</a></h2><ul><li>Right-click an IP address, and click <strong>Traceroute</strong>.</li></ul><p>This action will perform a Traceroute, displaying the number of hops taken by the host machine to reach the target.</p><h2 id="perform-port-scanning-on-the-target-host" tabindex="-1">Perform Port Scanning on the Target Host <a class="header-anchor" href="#perform-port-scanning-on-the-target-host" aria-label="Permalink to &quot;Perform Port Scanning on the Target Host&quot;">​</a></h2><ul><li>Next select the <strong>Port Scanner</strong> on the left pane.</li><li>Enter the IP address of the target machine under <strong>Destination Address List</strong> section, and click <strong>Add</strong>.</li></ul><p>This action will list all the ports associated with the target, along with the <strong>port type, keyword, risk, and description</strong>, as shown in the following screenshot:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c7ebf540a2bb39c7a989b87716bc23fd1151dbb8/megaPing-PortScanner.png" alt="alt text" title="MegaPing Port Scanner"></p><p>Note: You also can generate a report in HTML file on every scan.</p><p><strong>Conclusion</strong>: MegaPing security scanner checks your network for potential vulnerabilities that could be used for a bad actor.</p>',24)]))}const p=t(r,[["render",i]]);export{u as __pageData,p as default};
